UPDATE species_profiles
SET
  market_weight_note = CASE canonical_name
    WHEN '광어' THEN '1kg 미만은 살 두께와 수율이 아쉽습니다. 1.5kg 이상부터 회감으로 안정적이고, 2~3kg급은 맛과 가격 균형이 좋습니다. 3kg 이상 대광어는 탄력과 단맛, 두툼한 식감이 강점이라 숙성 회로도 잘 맞습니다.'
    WHEN '우럭' THEN '500~800g급은 대중적인 활어 규격입니다. 1kg 전후부터 살이 두툼하고 탕까지 쓰기 좋으며, 우럭은 머리가 커 순살 수율이 낮으므로 작은 개체 여러 마리보다 큰 개체 한 마리가 회 양과 식감에서 유리합니다.'
    WHEN '참돔' THEN '참돔은 순살 수율이 약 35%라 3인 회는 1.5~1.8kg, 5인 회는 2.5~3kg급이 실사용 기준입니다. 2kg 이상 대도미는 살 두께, 머리·뼈 활용, 숙성·초밥 적성이 좋아지고 1kg대는 담백하지만 부위감은 적습니다.'
    WHEN '감성돔' THEN '30cm대는 살이 가볍고 빠르게 먹는 회에 맞습니다. 40cm 이상 대물은 겨울에 맛이 좋지만 껍질이 질겨 껍질회보다는 일반 회가 안전합니다. 산란 직후에는 살이 빠질 수 있어 체고와 배 탄력을 같이 봅니다.'
    WHEN '돌도다리' THEN '작은 도다리류는 세꼬시나 탕으로 쓰기 좋고, 600~900g 이상이면 뼈를 빼고 일반 회처럼 먹기 편합니다. 1kg 이상은 살 두께와 수율이 좋아지지만 산란 직후에는 살이 무를 수 있어 원문 표기와 상태를 같이 봅니다.'
    WHEN '능성어' THEN '1kg대도 고급 바리류 맛은 나지만 살 두께와 부위감은 2kg 이상부터 안정적입니다. 3kg 이상은 숙성하면 감칠맛이 좋아지고 맑은탕·조림까지 가치가 큽니다. 자바리와 혼동 표기가 잦으니 이름을 꼭 분리해서 봅니다.'
    WHEN '농어' THEN '농어는 2kg 이상, 대략 50cm 이상을 권장합니다. 3kg 이상 자연산은 결이 살아 있고 구이에서도 기름이 배어 깊은 맛이 나지만, 작은 농어는 맛이 밋밋하고 수율도 아쉬울 수 있습니다.'
    WHEN '자바리' THEN '1kg 전후는 방류나 어린 개체가 섞일 수 있고, 진짜 성어는 드뭅니다. 2~3kg 이상부터 바리류 특유의 탄력과 감칠맛이 살아나며, 큰 성어는 여러 부위로 나눠 먹는 코스 가치가 커 숙성 회로도 좋습니다.'
    WHEN '점성어' THEN '점성어는 민어 대체·뷔페용으로 쓰이는 일이 많아 작은 개체나 저가품은 맛이 밋밋할 수 있습니다. 4~6kg급 큰 개체는 살 두께와 수율이 좋아 두툼하게 썰기 좋고, 민어나 참돔으로 둔갑한 표기는 피해야 합니다.'
    WHEN '시마아지' THEN '일본 양식 시마아지는 보통 1~2kg급으로 출하됩니다. 1kg대는 산뜻하고 단정한 전갱이류 식감, 2kg 전후는 지방과 감칠맛이 더 좋습니다. 상처가 많은 B급은 선도 저하가 빠를 수 있어 상태를 봅니다.'
    WHEN '줄돔' THEN '500g 안팎의 작은 줄돔은 쫄깃하지만 살이 적어 구이나 세꼬시에 가깝습니다. 1kg 이상부터 회로 먹을 살 두께가 나오고, 2kg급은 가격이 크게 뛰지만 숙성했을 때 고소함과 식감이 좋아집니다.'
    WHEN '돌돔' THEN '300~500g급 작은 돌돔은 소금구이나 세꼬시로 무난합니다. 1kg 한 마리부터 회 가치가 뚜렷하고, 2kg 이상은 비싸지만 배바지살의 사각거리는 식감과 누적되는 고소함이 강점입니다.'
    WHEN '잿방어' THEN '잿방어는 3kg대부터 회감으로 안정적이고, 5kg 이상이면 간파치 특유의 탄력과 기름, 부위감이 살아납니다. 작은 개체는 담백하고 산뜻하지만 살이 얇고, 큰 개체는 몇 시간 이상 숙성했을 때 단맛이 잘 납니다.'
    WHEN '부시리' THEN '산지 활어라면 작은 부시리도 꼬들꼬들하게 맛있지만, 택배 필렛은 1~2kg급보다 5kg 이상 중대형 원어가 유리합니다. 80cm 이상 대부시리는 방어처럼 부위감이 생기고, 숙성하면 감칠맛과 단맛이 올라옵니다.'
    WHEN '연어' THEN '회용 대서양연어 원어는 5~6kg급 유통이 흔합니다. 큰 원어에서 나온 필렛은 뱃살 지방과 등살 식감 차이가 뚜렷하고, 200~300g 소분은 먹기 편하지만 개체 크기 판단은 어렵습니다. 선도와 냉장/해동 관리가 맛을 크게 좌우합니다.'
    WHEN '개숭어' THEN '가숭어·밀치 계열은 1kg 미만이면 지방이 부족해 세꼬시나 가벼운 회에 맞고, 1.5~2kg은 가장 무난합니다. 2.5kg 이상 대물은 뱃살 두께와 아삭한 식감, 수율이 좋아 겨울철 고소함을 기대할 수 있습니다.'
    WHEN '도다리' THEN '작은 도다리는 세꼬시로 먹기 좋고, 800~900g 정도면 뼈를 빼 일반 회처럼 먹기 편합니다. 큰 도다리는 포를 떠서 먹는 쪽이 낫고, 산란 직후에는 살이 얇고 무를 수 있어 회보다는 쑥국·탕을 봅니다.'
    WHEN '도미' THEN '시장명 도미는 참돔 기준으로 보면 1.5~1.8kg이 소인원 회, 2.5~3kg이 넉넉한 회 기준입니다. 2kg 이상 대도미는 숙성·초밥·머리구이 활용도가 좋고, 1kg대는 담백하지만 두께와 부위감은 적습니다.'
    WHEN '방어' THEN '3~6kg은 소방어, 6~8kg은 중방어, 8kg 이상은 대방어로 보는 편입니다. 8kg 이상부터 지방과 부위감이 확실하고, 10kg 안팎 특대급은 뱃살·가마살의 고소함이 강합니다. 작은 방어는 담백하지만 대방어 맛과는 다릅니다.'
    WHEN '뱅에돔' THEN '30cm 전후는 마릿수와 가벼운 회에 맞고, 40cm급 대물은 살 두께와 기름이 좋아집니다. 0.6~1kg급은 소량 회로 무난하지만 큰 개체일수록 숙성했을 때 향과 감칠맛이 살아납니다.'
    WHEN '보리숭어' THEN '보리숭어는 1~1.5kg급이 무난하고, 2kg 이상이면 살 두께와 수율이 좋아집니다. 너무 작은 개체는 살이 얇고 향이 도드라질 수 있어 세꼬시나 탕에 가깝고, 산지와 물내 여부를 꼭 봅니다.'
    WHEN '복어' THEN '양식 참복 700~800g은 탕용으로 균일한 대중 규격입니다. 1kg 이상이면 회·수육에서 살감이 좋아지고, 큰 수컷은 이리 요리 가치가 큽니다. 복어류는 크기보다 식용 가능 종과 전문 손질 여부가 먼저입니다.'
    WHEN '붉바리' THEN '500g 이하 30cm급은 살이 적고 담백한 편입니다. 1kg 이상 성체급부터 기름과 쫄깃한 식감이 살아나며, 40cm 전후는 회로 권할 만합니다. 활어보다 숙성 선어에서 차진 식감과 감칠맛이 좋다는 평가가 많습니다.'
    WHEN '숭어' THEN '숭어류는 1kg 미만이면 지방이 부족해 세꼬시나 가벼운 회에 가깝고, 1.5~2kg은 균형이 좋습니다. 2.5kg 이상 대물은 뱃살이 두껍고 아삭한 식감과 수율이 좋아지지만, 산지 물내와 배 탄력이 맛을 좌우합니다.'
    WHEN '참복' THEN '참복은 700~800g 양식 규격도 탕으로 좋지만, 1kg 이상부터 회·수육의 살감이 안정됩니다. 1.3~1.5kg급은 코스용으로 쓰기 좋고, 큰 수컷은 이리 요리 가치가 큽니다. 전문 손질은 필수입니다.'
    ELSE market_weight_note
  END,
  info_sources = CASE canonical_name
    WHEN '광어' THEN '["https://merriman-and-co.tistory.com/870","https://my-di-storage.tistory.com/128","https://funding.tistory.com/entry/%ED%9A%9F%EA%B0%90%EC%9C%BC%EB%A1%9C-%EC%A6%90%EA%B2%A8%EB%A8%B9%EB%8A%94-%EA%B4%91%EC%96%B4-%EC%88%AD%EC%96%B4-%EC%9A%B0%EB%9F%AD-%EA%B0%80%EA%B2%A9%EB%B9%84%EA%B5%90-%EA%BF%80%ED%8C%81-%EB%AA%A8%EC%9D%8C%EC%A7%91-%ED%95%9C-%EB%B2%88%EC%97%90-%EB%B3%B4%EA%B8%B0"]'
    WHEN '참돔' THEN '["https://slds2.tistory.com/2283","https://slds2.tistory.com/3708","https://slds2.tistory.com/70"]'
    WHEN '감성돔' THEN '["https://slds2.tistory.com/3708","https://slds2.tistory.com/1115","https://www.ocean-fishing.com/fish/14"]'
    WHEN '돌도다리' THEN '["https://joon-hobby.com/75","https://fishingseasons.co.kr/contents_view_detail.asp?b_no=15245","https://weekly.chosun.com/news/articleView.html?idxno=17109"]'
    WHEN '능성어' THEN '["https://slds2.tistory.com/2506","https://mlbpark.donga.com/mp/b.php?b=bullpen&id=201711280011458492&m=view&p=3931&query=&select=&site=donga.com&user=","https://sakgane.tistory.com/5997"]'
    WHEN '농어' THEN '["https://slds2.tistory.com/3263","https://v.daum.net/v/U9su1z2XU7","https://slds2.tistory.com/1678"]'
    WHEN '자바리' THEN '["https://hongikstory.tistory.com/912","https://www.yna.co.kr/amp/view/AKR20210305067200056","https://www.moneys.co.kr/article/2019031216098094072"]'
    WHEN '점성어' THEN '["https://slds2.tistory.com/3758","https://animalia.bio/ko/red-drum","https://cilius.tistory.com/154"]'
