    WHEN '줄돔' THEN '["https://slds2.tistory.com/2655","https://m.wikitree.co.kr/articles/1095098","https://handhoons.tistory.com/entry/%EC%83%9D%EC%84%A0%EB%A6%AC%EB%B7%B0-%EB%8F%8C%EB%8F%94%EC%A4%84%EB%8F%94%EC%9A%94%EB%A6%AC"]'
    WHEN '돌돔' THEN '["https://m.wikitree.co.kr/articles/1095098","https://slds2.tistory.com/3610","https://jejunim1.tistory.com/872"]'
    WHEN '잿방어' THEN '["https://fish.candopost.com/fishery/grace/great-amberjack/","https://en.wikipedia.org/wiki/Greater_amberjack","https://slds2.tistory.com/3643"]'
    WHEN '부시리' THEN '["https://slds2.tistory.com/3643","https://www.cashfeed.co.kr/posts/15030610","https://fishingseasons.co.kr/contents_view_detail.asp?b_no=1894"]'
    WHEN '연어' THEN '["https://www.midafood.com/products/salmon-atlantic-whole-gutted","https://display.cjonstyle.com/nfront/content/pick/%EC%97%B0%EC%96%B4-%EC%B6%94%EC%B2%9C/index.html","https://www.seafoodsource.com/seafoodhandbook/finfish/salmon-atlantic"]'
    WHEN '개숭어' THEN '["https://etaz.tistory.com/entry/%EA%B0%80%EC%88%AD%EC%96%B4%EC%99%80-%EC%88%AD%EC%96%B4-%EC%99%84%EB%B2%BD-%EA%B5%AC%EB%B6%84-%EA%B0%80%EC%9D%B4%EB%93%9C-%EB%B0%80%EC%B9%98-%EC%A0%9C%EC%B2%A0%EB%B6%80%ED%84%B0-%EA%B8%B0%EC%83%9D%EC%B6%A9-%EA%B1%B1%EC%A0%95-%EC%97%86%EB%8A%94-%EC%84%AD%EC%B7%A8%EB%B2%95%EA%B9%8C%EC%A7%80-%EC%B4%9D%EC%A0%95%EB%A6%AC","https://pionani.tistory.com/entry/%EA%B2%A8%EC%9A%B8-%EA%B0%80%EC%84%B1%EB%B9%84-%ED%9A%9F%EA%B0%90-%EA%B0%80%EC%88%AD%EC%96%B4-aka-%EB%B0%80%EC%B9%98-%EC%B0%B8%EC%88%AD%EC%96%B4%EC%9D%98-%EC%9E%AC%EB%B0%9C%EA%B2%AC","https://news.mt.co.kr/mtview.php?no=2020041415144439296"]'
    WHEN '도다리' THEN '["https://joon-hobby.com/75","https://fishingseasons.co.kr/contents_view_detail.asp?b_no=15245","https://www.donga.com/news/Economy/article/all/20130324/53940751/2"]'
    WHEN '도미' THEN '["https://slds2.tistory.com/2283","https://slds2.tistory.com/3708","https://slds2.tistory.com/70"]'
    WHEN '방어' THEN '["https://m.health.chosun.com/svc/news_view.html?contid=2024010801932","https://www.busan.com/view/busan/view.php?code=2024010317433866335","https://www.edaily.co.kr/News/Read?mediaCodeNo=257&newsId=01636726622716224"]'
    WHEN '뱅에돔' THEN '["https://slds2.tistory.com/3263","https://slds2.tistory.com/2506","https://www.bfg-fishing.com/fish-species/sea-bream"]'
    WHEN '보리숭어' THEN '["https://news.mt.co.kr/mtview.php?no=2020041415144439296","https://plantfood.tistory.com/entry/%EC%88%AD%EC%96%B4-%ED%9A%A8%EB%8A%A5%C2%B7%EC%97%B4%EB%9F%89%C2%B7%ED%99%9C%EC%9A%A9%EC%84%B1%C2%B7%EC%97%AD%EC%82%AC%C2%B7%EC%9C%A0%EB%9E%98","https://suwonzip.tistory.com/12"]'
