    WHEN '우럭' THEN '["https://junyeop0319.tistory.com/entry/%ED%9A%8C-%EC%88%9C%EC%82%B4-%EB%AC%B4%EA%B2%8C-%EA%B4%91%EC%96%B4-%EC%9A%B0%EB%9F%AD-%EC%88%9C%EC%82%B4%EB%AC%B4%EA%B2%8C-%ED%9A%8C-%EC%88%98%EC%9C%A8-%EB%B9%84%EA%B5%90","https://slds2.tistory.com/485","https://sinabeuro948.tistory.com/2077"]'
    WHEN '참복' THEN '["https://v.daum.net/v/ZgzYnIDghV","https://www.newsis.com/view/NISX20170101_0014613766","https://en.wikipedia.org/wiki/Takifugu_rubripes"]'
